results = globals()['var_functions.execute_python:50']

project_count = results['count']
projects = results['projects']

print('Found', project_count, 'projects related to emergency or FEMA')
print('\nProjects Summary:')
for i, proj in enumerate(projects, 1):
    print(f"""{i}. {proj['Project_Name']}
   Funding: {proj['Funding_Source']}
   Amount: ${proj['Amount']:,}
   Status: {proj['Status']}
   Type: {proj['Type']}
   Topic: {proj['Topic']}
""")

# Build final answer
answer = f"""Found {project_count} projects related to 'emergency' or 'FEMA':

"""

for proj in projects:
    answer += f"""Project Name: {proj['Project_Name']}
Funding Source: {proj['Funding_Source']}
Amount: ${proj['Amount']:,}
Status: {proj['Status']}
Topic: {proj['Topic']}

"""

print('__RESULT__:')
print(json.dumps(answer))
